import axios from "axios";

// 1️⃣ Create an Axios instance
const api = axios.create({
  baseURL: "http://localhost:5000/api", // backend URL
  headers: {
    "Content-Type": "application/json",
  },
});

// 2️⃣ Request interceptor to attach JWT automatically
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("nfxtoken");
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// 3️⃣ Login function
export const loginUser = async ({ email, password }) => {
  const response = await api.post("/auth/login", { email, password });
  // Save token and basic user info in localStorage
  if (response.data.token) {
    localStorage.setItem("nfxtoken", response.data.token);
    localStorage.setItem("userEmail", response.data.email);
    localStorage.setItem("userName", response.data.name);
  }
  return response.data;
};

// 4️⃣ Signup function
export const signupUser = async ({ name, email, password }) => {
  const response = await api.post("/auth/signup", { name, email, password });
  return response.data;
};

// 5️⃣ Logout function
export const logoutUser = () => {
  localStorage.removeItem("nfxtoken");
  localStorage.removeItem("userEmail");
  localStorage.removeItem("userName");
};

// 6️⃣ Example protected API call
export const getDashboardData = async () => {
  const response = await api.get("/dashboard"); // token automatically attached
  return response.data;
};

export default api;
